const form = $input.first().json;

const config = {
  recent_months:     6,
  lookback_months:  18,
  lang_delta_pct:   15,
  burst_multiplier:  2.0,
  min_stars:        10,
  velocity_repos:    5,
  velocity_z_thresh: 2.0,
};

const org = (form['GitHub Org Slug'] || '').trim().toLowerCase();
const name = (form['Company Name'] || '').trim();

if (!org || !name) {
  throw new Error('Company Name and GitHub Org Slug are required.');
}

const graphql_query =
  '{ organization(login: "' + org + '") {' +
  '  repositories(first: 100, orderBy: {field: PUSHED_AT, direction: DESC}, privacy: PUBLIC) {' +
  '    nodes {' +
  '      name nameWithOwner stargazerCount forkCount isFork' +
  '      createdAt pushedAt' +
  '      primaryLanguage { name }' +
  '      languages(first: 15, orderBy: {field: SIZE, direction: DESC}) {' +
  '        edges { size node { name } } totalSize' +
  '      }' +
  '      repositoryTopics(first: 10) { nodes { topic { name } } }' +
  '    }' +
  '  }' +
  '} }';

return [{
  json: {
    name,
    org,
    sector:       (form['Sector'] || 'Technology').trim(),
    ticker:       (form['Stock Ticker'] || '').trim(),
    github_token: (form['GitHub Token'] || '').trim(),
    groq_api_key: (form['Groq API Key'] || '').trim(),
    config,
    graphql_query,
    run_ts:    new Date().toISOString(),
    run_ts_ms: Date.now(),
  }
}];

const item = $input.first().json;              // GraphQL response
const ctx  = $('Company Input').first().json;  // original context
const cfg  = ctx.config;

// ── Extract repos from GraphQL response ───────────────────────────
const gql = item.data && item.data.organization;
if (!gql || !gql.repositories) {
  return [{ json: {
    ...item,
    pipeline_status: 'GQL_ERROR',
    error: JSON.stringify(item.errors || item).slice(0, 400),
  }}];
}

const raw      = gql.repositories.nodes || [];
const now      = Date.now();
const DAY      = 86400000;
const recCut   = now - cfg.recent_months   * 30 * DAY;
const baseCut  = now - cfg.lookback_months * 30 * DAY;
const basePeriod = cfg.lookback_months - cfg.recent_months;

// ── Normalise every repo ──────────────────────────────────────────
const repos = raw.map(r => {
  const topics     = (r.repositoryTopics?.nodes || []).map(n => n.topic?.name || '');
  const langEdges  = r.languages?.edges || [];
  const totalBytes = r.languages?.totalSize || 1;
  const langDist   = {};
  for (const e of langEdges) {
    langDist[e.node.name] = Math.round(e.size / totalBytes * 1000) / 10; // % of bytes
  }
  return {
    name:         r.name,
    full_name:    r.nameWithOwner,
    stars:        r.stargazerCount || 0,
    forks:        r.forkCount      || 0,
    is_fork:      r.isFork,
    created_ms:   r.createdAt ? new Date(r.createdAt).getTime() : 0,
    pushed_ms:    r.pushedAt  ? new Date(r.pushedAt ).getTime() : 0,
    primary_lang: r.primaryLanguage?.name || null,
    lang_dist:    langDist,
    topics,
    days_since_push: r.pushedAt ? Math.round((now - new Date(r.pushedAt).getTime()) / DAY) : 9999,
  };
});

const nonFork    = repos.filter(r => !r.is_fork);
const totalStars = nonFork.reduce((s, r) => s + r.stars, 0);
const active90   = nonFork.filter(r => r.days_since_push <= 90 ).length;
const stale365   = nonFork.filter(r => r.days_since_push > 365).length;

// ── Time cohorts ──────────────────────────────────────────────────
const recNF = nonFork.filter(r => r.created_ms >= recCut);
const oldNF = nonFork.filter(r => r.created_ms >= baseCut && r.created_ms < recCut);

const mRate    = recNF.length / cfg.recent_months;
const mBase    = oldNF.length / basePeriod || 0;
const bRatio   = mBase > 0 ? mRate / mBase : 0;
const hasBurst = bRatio >= cfg.burst_multiplier;

// ── Star-weighted language distribution per cohort ────────────────
function weightedLangDist(cohort) {
  const agg = {};
  let totalW = 0;
  for (const r of cohort) {
    if (r.stars < cfg.min_stars) continue;
    const w = Math.max(1, r.stars);
    totalW += w;
    for (const [lang, pct] of Object.entries(r.lang_dist)) {
      agg[lang] = (agg[lang] || 0) + pct * w;
    }
  }
  if (!totalW) return {};
  return Object.fromEntries(
    Object.entries(agg).map(([k, v]) => [k, Math.round(v / totalW * 10) / 10])
  );
}

const recDist  = weightedLangDist(recNF);
const oldDist  = weightedLangDist(oldNF);
const allLangs = new Set([...Object.keys(recDist), ...Object.keys(oldDist)]);

// ── Language deltas ───────────────────────────────────────────────
const deltas = [];
for (const lang of allLangs) {
  const rec  = recDist[lang] || 0;
  const old  = oldDist[lang] || 0;
  const diff = rec - old;
  const rel  = old > 0 ? Math.abs(diff) / old * 100 : (rec > 0.5 ? 100 : 0);
  const isNew     = old < 0.1 && rec > 0.5;
  const isDropped = rec < 0.1 && old > 0.5;
  if (rel >= cfg.lang_delta_pct || isNew || isDropped) {
    deltas.push({
      language:   lang,
      recent_pct: Math.round(rec * 10) / 10,
      older_pct:  Math.round(old * 10) / 10,
      delta_pp:   Math.round(diff * 10) / 10,
      rel_chg:    Math.round(rel),
      direction:  isNew ? 'EMERGING' : isDropped ? 'ABANDONED' : diff > 0 ? 'RISING' : 'DECLINING',
      is_new:     isNew,
      is_dropped: isDropped,
    });
  }
}
deltas.sort((a, b) => Math.abs(b.delta_pp) - Math.abs(a.delta_pp));

// ── AI/ML topic focus ratio ───────────────────────────────────────
const AI_TAGS = new Set(['machine-learning','deep-learning','llm','large-language-model',
  'neural-network','nlp','computer-vision','reinforcement-learning','generative-ai',
  'transformer','diffusion','multimodal','ai','pytorch','tensorflow','cuda','inference','fine-tuning']);
const aiRatio = (cohort) =>
  cohort.filter(r => r.topics.some(t => AI_TAGS.has(t))).length / Math.max(1, cohort.length);
const aiRec = aiRatio(recNF);
const aiOld = aiRatio(oldNF);

// ── Top repos for velocity analysis ──────────────────────────────
const topRepos = nonFork
  .filter(r => r.stars >= cfg.min_stars)
  .sort((a, b) => b.stars - a.stars)
  .slice(0, cfg.velocity_repos)
  .map(r => ({
    name:           r.name,
    full_name:      r.full_name,
    stars:          r.stars,
    primary_lang:   r.primary_lang,
    days_since_push:r.days_since_push,
    commit_url:     `https://api.github.com/repos/${r.full_name}/stats/commit_activity`,
  }));

return [{
  json: {
    // carry forward
    name:         item.name,
    org:          item.org,
    sector:       item.sector,
    ticker:       item.ticker,
     config:       item.config,
    run_ts:       item.run_ts,
    pipeline_status: 'OK',

    repo_stats: {
      total_fetched: raw.length,
      non_fork:      nonFork.length,
      total_stars:   totalStars,
      avg_stars:     nonFork.length ? Math.round(totalStars / nonFork.length) : 0,
      active_90d:    active90,
      stale_365d:    stale365,
      rec_cohort_size: recNF.length,
      old_cohort_size: oldNF.length,
    },
    burst: {
      has_burst:    hasBurst,
      ratio:        Math.round(bRatio * 100) / 100,
      monthly_rec:  Math.round(mRate * 10) / 10,
      monthly_base: Math.round(mBase * 10) / 10,
      rec_count:    recNF.length,
      signal:       hasBurst
        ? `BURST DETECTED: ${recNF.length} new repos in ${cfg.recent_months}m vs ${Math.round(mBase*10)/10}/m historical baseline (${Math.round(bRatio*10)/10}x)`
        : 'NORMAL — repo creation rate within historical baseline',
    },
    language: {
      recent_dist:    recDist,
      older_dist:     oldDist,
      deltas,
      shift_detected: deltas.length > 0,
      rising:    deltas.filter(d => d.direction === 'RISING'    || d.direction === 'EMERGING'),
      declining: deltas.filter(d => d.direction === 'DECLINING' || d.direction === 'ABANDONED'),
      new_langs: deltas.filter(d => d.is_new),
      dropped:   deltas.filter(d => d.is_dropped),
    },
    ai_focus: {
      recent_ratio: Math.round(aiRec * 100),
      older_ratio:  Math.round(aiOld * 100),
      delta_pp:     Math.round((aiRec - aiOld) * 100),
      increasing:   (aiRec - aiOld) > 0.1,
    },
    top_repos: topRepos,
  }
}];

const d     = $input.first().json;
const token = d.github_token;

const HEADERS = {
  'Authorization':        `Bearer ${token}`,
  'Accept':               'application/vnd.github+json',
  'X-GitHub-Api-Version': '2022-11-28',
  'User-Agent':           'TSDSA-v2/1.0',
};

async function fetchRepoCommits(repo) {
  const since = new Date(Date.now() - 365 * 86400000).toISOString();
  const url = `https://api.github.com/repos/${repo.full_name}/commits?per_page=100&since=${since}`;
  try {
    const resp = await $helpers.httpRequest({ method: 'GET', url, headers: HEADERS });
    const commits = Array.isArray(resp) ? resp : [];
    return {
      repo:         repo.name,
      full_name:    repo.full_name,
      stars:        repo.stars,
      language:     repo.primary_lang,
      commits,
      fetch_status: 'OK',
    };
  } catch (e) {
    const status = e.message.includes('404') ? 'EMPTY_REPO'
                 : e.message.includes('409') ? 'NO_COMMITS'
                 : 'FAILED';
    return {
      repo:         repo.name,
      full_name:    repo.full_name,
      stars:        repo.stars,
      language:     repo.primary_lang,
      commits:      [],
      fetch_status: status,
      error:        e.message.slice(0, 120),
    };
  }
}

const settled = await Promise.allSettled(
  (d.top_repos || []).map(r => fetchRepoCommits(r))
);

const commit_data = settled.map(s =>
  s.status === 'fulfilled' ? s.value
  : { repo: '?', commits: [], fetch_status: 'FAILED', error: String(s.reason) }
);

const ok_count = commit_data.filter(r => r.fetch_status === 'OK').length;
const velocity_fetch_status =
  ok_count === 0                  ? 'FAILED'
  : ok_count < commit_data.length ? 'PARTIAL'
  : 'OK';

return [{ json: { ...d, commit_data, velocity_fetch_status } }];

const ctx = $('Company Input').first().json;
const d = { ...$input.first().json, config: ctx.config, name: ctx.name, org: ctx.org };

// ── Compose data summary for the model ────────────────────────────
const topLangsStr = Object.entries(d.language.recent_dist || {})
  .sort(([,a],[,b]) => b - a).slice(0, 6)
  .map(([l, p]) => `${l}:${p}%`).join(', ') || 'n/a';

const deltaStr = (d.language.deltas || []).slice(0, 6)
  .map(x => `${x.language} ${x.direction} (${x.rel_chg}% relative, ${x.delta_pp}pp)`)
  .join('; ') || 'none detected';

const velStr = (d.velocity.signals || [])
  .filter(s => s.status === 'analysed')
  .map(s => `${s.repo}[${s.language||'?'},${s.stars}★]: z=${s.z_score}, ${s.baseline_wkly}→${s.recent_wkly} commits/wk, momentum=${s.momentum_pct !== null ? s.momentum_pct+'%' : 'n/a'}`)
  .join(' | ') || 'no velocity data';

const topReposStr = (d.top_repos || [])
  .map(r => `${r.name}(${r.stars}★,${r.primary_lang||'?'},${r.days_since_push}d)`)
  .join(', ');

const systemPrompt =
  'You are a senior investment analyst specialising in AI/technology companies. ' +
  'You analyse engineering signals from GitHub to identify technology strategy direction. ' +
  'Respond ONLY with valid JSON — no markdown, no explanation, no code fences.';

const userPrompt =
  `Analyse the following GitHub engineering signals for ${d.name} (${d.sector}):

COMPANY: ${d.name} | ORG: ${d.org} | SECTOR: ${d.sector}
REPO HEALTH: ${d.repo_stats.non_fork} public repos | ${d.repo_stats.total_stars.toLocaleString()} total stars | ${d.repo_stats.active_90d} active (90d) | ${d.repo_stats.stale_365d} stale (365d+)
RECENT COHORT: ${d.repo_stats.rec_cohort_size} repos created in last ${d.config.recent_months} months
OLDER COHORT:  ${d.repo_stats.old_cohort_size} repos created in prior ${d.config.lookback_months - d.config.recent_months} months

REPO CREATION BURST: ${d.burst.signal}
AI/ML TOPIC FOCUS: recent=${d.ai_focus.recent_ratio}% repos | older=${d.ai_focus.older_ratio}% repos | delta=${d.ai_focus.delta_pp}pp

TOP LANGUAGES (recent, star-weighted): ${topLangsStr}
LANGUAGE SHIFTS (≥${d.config.lang_delta_pct}% relative change): ${deltaStr}

COMMIT VELOCITY (top repos by stars):
${velStr}

TOP REPOS: ${topReposStr}

Return ONLY this JSON:
{
  "signal_summary": "3-4 sentence investment-grade assessment of engineering direction",
  "velocity_assessment": "1-2 sentences on commit momentum and what it implies",
  "technology_direction": "Where is engineering effort moving? What does the language/repo data suggest about strategy?",
  "key_risks": ["risk 1", "risk 2", "risk 3"],
  "key_opportunities": ["opportunity 1", "opportunity 2", "opportunity 3"],
  "comparable_moves": "Has any comparable company made a similar engineering shift? Brief 1-sentence context.",
  "flags": ["FLAG1", "FLAG2"],
  "intensity": "NONE or LOW or MEDIUM or HIGH or CRITICAL",
  "confidence_score": 0-100,
  "composite_signal_score": 0-100,
  "investment_implication": "BULLISH or BEARISH or NEUTRAL or WATCH"
}`;

return [{
  json: {
    ...d,
    groq_payload: JSON.stringify({
      model: 'llama-3.1-8b-instant',
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user',   content: userPrompt   },
      ],
      temperature: 0.2,
      max_tokens:  900,
      response_format: { type: 'json_object' },
    }),
  }
}];

const groqResponse = $input.first().json;                  // Groq output — choices only
const cleanPipe    = $('Build Groq Prompt').first().json;  // full pipeline data

// ── Safe deep getter ──────────────────────────────────────────────────────────
const g = (obj, ...path) => {
  let cur = obj;
  for (const k of path) {
    if (cur == null) return undefined;
    cur = Array.isArray(cur) && typeof k === 'number' ? cur[k] : (cur[k] ?? undefined);
  }
  return cur;
};
const gd = (obj, ...args) => {
  const def  = args[args.length - 1];
  const path = args.slice(0, -1);
  const val  = g(obj, ...path);
  return val != null ? val : def;
};

const cfg = cleanPipe.config || {};
const BURST_THRESHOLD = cfg.burst_multiplier ?? 2.0;
const LANG_DELTA_PCT  = cfg.lang_delta_pct   ?? 15;
const VEL_Z_THRESH    = cfg.velocity_z_thresh ?? 2.0;

// ── Parse Groq response ───────────────────────────────────────────────────────
let ai = {};
try {
  const choices = groqResponse.choices || [];
  const content = choices[0]?.message?.content || '{}';
  ai = JSON.parse(content);
} catch(e) { ai = {}; }

const AI_DEFAULTS = {
  signal_summary:        'AI analysis unavailable — check Groq API key',
  velocity_assessment:   'Velocity data could not be retrieved.',
  technology_direction:  'Insufficient data for direction signal.',
  key_risks:             ['Data quality risk: velocity endpoint unavailable'],
  key_opportunities:     [],
  comparable_moves:      '',
  flags:                 [],
  intensity:             'NONE',
  confidence_score:      0,
  composite_signal_score:0,
  investment_implication:'NEUTRAL',
};
for (const [k, v] of Object.entries(AI_DEFAULTS)) {
  if (ai[k] == null) ai[k] = v;
}

// ── Rule flags ────────────────────────────────────────────────────────────────
const burstRatio = gd(cleanPipe, 'burst', 'ratio', 0);
const burstBase  = gd(cleanPipe, 'burst', 'monthly_base', 0);
const hasBurst   = burstBase > 0 && burstRatio >= BURST_THRESHOLD;

const ruleFlags = [];
if (hasBurst)                                                 ruleFlags.push('REPO_BURST');
if (gd(cleanPipe,'language','shift_detected',false))          ruleFlags.push('LANGUAGE_SHIFT');
if (gd(cleanPipe,'ai_focus','increasing',false))              ruleFlags.push('AI_FOCUS_INCREASING');
if (gd(cleanPipe,'velocity','acceleration_count',0) > 0)      ruleFlags.push('VELOCITY_ACCELERATION');
if (gd(cleanPipe,'velocity','deceleration_count',0) > 0)      ruleFlags.push('VELOCITY_DECELERATION');
if ((gd(cleanPipe,'language','new_langs',[]) || []).length > 0) ruleFlags.push('NEW_LANGUAGE_ADOPTION');

const allFlags = [...new Set([...ruleFlags, ...(ai.flags || [])])];

// ── Composite score ───────────────────────────────────────────────────────────
let ruleScore = 0;
if (hasBurst) ruleScore += Math.min(30, burstRatio * 10);
const deltas = gd(cleanPipe, 'language', 'deltas', []) || [];
if (deltas.length) ruleScore += Math.min(25, deltas.length * 5);
if (gd(cleanPipe,'ai_focus','increasing',false)) ruleScore += 10;
const anomalyCount = gd(cleanPipe,'velocity','anomaly_count',0);
if (anomalyCount > 0) ruleScore += Math.min(20, anomalyCount * 10);

const composite = Math.min(100, Math.round(ai.composite_signal_score * 0.6 + ruleScore * 0.4));

// ── Intensity ─────────────────────────────────────────────────────────────────
const ORD   = ['NONE','LOW','MEDIUM','HIGH','CRITICAL'];
const ruleI = composite >= 85 ? 'CRITICAL' : composite >= 65 ? 'HIGH' :
              composite >= 45 ? 'MEDIUM'   : composite >= 25 ? 'LOW'  : 'NONE';
const groqI = ORD.includes(ai.intensity) ? ai.intensity : 'NONE';
const finalI = ORD.indexOf(groqI) >= ORD.indexOf(ruleI) ? groqI : ruleI;

const IC = {CRITICAL:'#dc2626',HIGH:'#ef4444',MEDIUM:'#f59e0b',LOW:'#3b82f6',NONE:'#4b5563'};

// ── Evidence trail ────────────────────────────────────────────────────────────
const langEvidence = {
  category:      'language_shift',
  status:        deltas.length ? 'DETECTED' : 'NONE',
  threshold_pct: LANG_DELTA_PCT,
  items: deltas.slice(0,5).map(d => ({
    language: d.language, from_pct: d.older_pct,
    to_pct: d.recent_pct, rel_change_pct: d.rel_chg, direction: d.direction,
  })),
  summary: deltas.length
    ? `${deltas.length} language(s) shifted >${LANG_DELTA_PCT}% relative`
    : `No language shifts detected at >${LANG_DELTA_PCT}% threshold`,
};

const rs    = cleanPipe.repo_stats || {};
const burst = cleanPipe.burst      || {};
const repoEvidence = {
  category:         'repo_growth',
  status:           hasBurst ? 'BURST' : 'NORMAL',
  burst_ratio:      Math.round(burstRatio * 100) / 100,
  burst_threshold:  BURST_THRESHOLD,
  monthly_recent:   burst.monthly_rec  ?? 0,
  monthly_baseline: burst.monthly_base ?? 0,
  total_repos:      rs.non_fork   || 0,
  active_90d:       rs.active_90d || 0,
  stale_365d:       rs.stale_365d || 0,
  summary:          burst.signal  || 'Repo growth data unavailable',
};

const vel       = cleanPipe.velocity || {};
const velStatus = vel.status || 'UNAVAILABLE';
const velSigs   = (vel.signals || []).filter(s => s.status === 'OK');
const velEvidence = {
  category:           'velocity_signal',
  status:             velStatus,
  overall_trend:      vel.overall_trend || 'UNKNOWN',
  repos_analysed:     velSigs.length,
  repos_total:        (vel.signals || []).length,
  anomalies_detected: vel.anomaly_count || 0,
  top_anomaly:        vel.top_anomaly || null,
  items: velSigs.slice(0,3).map(s => ({
    repo: s.repo, z_score: s.z_score,
    baseline_wkly: s.baseline_wkly, recent_wkly: s.recent_wkly,
    direction: s.direction, momentum_pct: s.momentum_pct,
  })),
  summary: velStatus !== 'UNAVAILABLE'
    ? `Velocity ${velStatus}: ${vel.overall_trend || '?'}, ${vel.anomaly_count || 0} anomalies across ${velSigs.length} repos analysed`
    : 'Commit velocity data unavailable — endpoint did not return sufficient data',
};

const anomalyEvidence = {
  category:           'anomaly_detection',
  status:             (vel.anomaly_count || 0) > 0 ? 'DETECTED' : 'NONE',
  acceleration_count: vel.acceleration_count || 0,
  deceleration_count: vel.deceleration_count || 0,
  items: (vel.signals || []).filter(s => s.is_anomaly).map(s => ({
    repo: s.repo, direction: s.direction, z_score: s.z_score, signal: s.signal,
  })),
  summary: (vel.anomaly_count || 0) > 0
    ? `${vel.anomaly_count} velocity anomaly(ies) detected`
    : 'No velocity anomalies at current z-score threshold',
};

// ── Claims schema v2.0 ────────────────────────────────────────────────────────
const name = cleanPipe.name   || 'UNKNOWN';
const org  = cleanPipe.org    || '?';
const ts   = cleanPipe.run_ts || '';

const claim = {
  claim_id:       `TSDSA-${name.replace(/\s+/g,'_').toUpperCase()}-${ts.slice(0,10)}`,
  agent:          'TechStackDirectionalSignalAgent',
  schema_version: '2.0',
  timestamp:      ts,
  subject:        name,
  github_org:     org,
  sector:         cleanPipe.sector || '',
  claim_type:     'ENGINEERING_DIRECTION_DELTA',
  intensity:      finalI,
  intensity_color:IC[finalI] || '#4b5563',
  composite_score:composite,
  confidence:     ai.confidence_score,
  confidence_degraded: velStatus === 'UNAVAILABLE',
  investment_implication: ai.investment_implication,
  flags: allFlags,
  signals: {
    velocity_status: velStatus,
    language_shift:  deltas.length > 0,
    burst_detected:  hasBurst,
    ai_focus:        gd(cleanPipe,'ai_focus','increasing',false),
  },
  ai_analysis: {
    signal_summary:       ai.signal_summary,
    velocity_assessment:  ai.velocity_assessment,
    technology_direction: ai.technology_direction,
    comparable_moves:     ai.comparable_moves,
    key_risks:            ai.key_risks,
    key_opportunities:    ai.key_opportunities,
  },
  engineering_direction_delta: {
    rising_languages:    (gd(cleanPipe,'language','rising',   []) || []).map(x => x.language),
    declining_languages: (gd(cleanPipe,'language','declining',[]) || []).map(x => x.language),
    new_languages:       (gd(cleanPipe,'language','new_langs',[]) || []).map(x => x.language),
    abandoned_languages: (gd(cleanPipe,'language','dropped',  []) || []).map(x => x.language),
    repo_trend:          hasBurst ? 'ACCELERATING' : 'NORMAL',
    commit_trend:        vel.overall_trend || 'STABLE',
    velocity_status:     velStatus,
  },
  evidence: {
    language_shift:    langEvidence,
    repo_growth:       repoEvidence,
    velocity_signal:   velEvidence,
    anomaly_detection: anomalyEvidence,
  },
  risk_flags:        ai.key_risks,
  opportunity_flags: ai.key_opportunities,
  resolver_ready: true,
  human_review:   ['HIGH','CRITICAL'].includes(finalI),
};

return [{ json: { ...cleanPipe, claim } }];

const velData = $('Velocity Analysis').first().json;
const d = { ...velData, ...$input.first().json };
const cl    = d.claim;
const ai    = cl.ai_analysis;
const edd   = cl.engineering_direction_delta;
const la    = d.language;
const bd    = d.burst;
const va    = d.velocity;
const rs    = d.repo_stats;
const genAt = new Date(d.run_ts).toLocaleString('en-US',{dateStyle:'medium',timeStyle:'short'});

const IC = {CRITICAL:'#dc2626',HIGH:'#ef4444',MEDIUM:'#f59e0b',LOW:'#3b82f6',NONE:'#4b5563'};
const IB = {CRITICAL:'#2d0a0a',HIGH:'#1f0a0a',MEDIUM:'#1f1500',LOW:'#0a1020',NONE:'#111827'};
const FC = {
  REPO_BURST:'#8b5cf6', LANGUAGE_SHIFT:'#06b6d4', AI_FOCUS_INCREASING:'#10b981',
  VELOCITY_ACCELERATION:'#22c55e', VELOCITY_DECELERATION:'#f97316',
  NEW_LANGUAGE_ADOPTION:'#f59e0b',
};
const IMPL_C = {BULLISH:'#10b981',BEARISH:'#ef4444',WATCH:'#f59e0b',NEUTRAL:'#6b7280'};

const ic  = k => IC[k]  || '#4b5563';
const ibc = k => IB[k]  || '#111827';
const fc  = k => FC[k]  || '#6b7280';
const col = ic(cl.intensity);
const bg  = ibc(cl.intensity);

const pill = (text, c) =>
  `<span style="background:${c}18;color:${c};border:1px solid ${c}33;` +
  `padding:3px 10px;border-radius:3px;font-size:9px;font-weight:700;letter-spacing:.5px;` +
  `white-space:nowrap;display:inline-block">${text.replace(/_/g,' ')}</span>`;

const implColor = IMPL_C[cl.investment_implication] || '#6b7280';
const implPill  = `<span style="background:${implColor}22;color:${implColor};border:1px solid ${implColor}44;` +
  `padding:4px 14px;border-radius:3px;font-size:11px;font-weight:700;letter-spacing:1px">` +
  `${cl.investment_implication}</span>`;

// ── Language delta rows ────────────────────────────────────────────
const langRows = (la.deltas || []).slice(0, 8).map(d => {
  const c    = d.direction === 'RISING' || d.direction === 'EMERGING' ? '#10b981' : '#ef4444';
  const icon = d.is_new ? '✦ NEW' : d.is_dropped ? '✕ GONE' :
               d.direction === 'RISING' ? '▲' : '▼';
  const c2   = d.is_new ? '#8b5cf6' : d.is_dropped ? '#4b5563' : c;
  return `<tr style="border-bottom:1px solid #1a2235">
    <td style="padding:6px 10px 6px 0;font-size:11px;color:#e2e8f0;font-weight:500">${d.language}</td>
    <td style="padding:6px 10px;font-size:11px;color:#4b5563;text-align:right">${d.older_pct}%</td>
    <td style="padding:6px 10px;font-size:11px;color:${c2};text-align:right;font-weight:700">${d.recent_pct}%</td>
    <td style="padding:6px 0 6px 10px;font-size:10px;color:${c2};white-space:nowrap">
      ${icon} ${d.rel_chg}% rel.</td>
  </tr>`;
}).join('') || `<tr><td colspan="4" style="padding:10px 0;font-size:10px;color:#374151">
  No shifts detected at ≥${d.config?.lang_delta_pct || 15}% relative threshold</td></tr>`;

// ── Velocity rows ──────────────────────────────────────────────────
const velRows = (va.signals || []).filter(s => s.status === 'analysed').map(s => {
  const c    = s.direction === 'ACCELERATION' ? '#10b981' : s.direction === 'DECELERATION' ? '#ef4444' : '#4b5563';
  const icon = s.is_anomaly ? (s.direction === 'ACCELERATION' ? '▲' : '▼') : '○';
  const mPill = s.momentum_pct !== null
    ? `<span style="color:${s.momentum_pct>0?'#10b981':'#ef4444'};font-size:9px">${s.momentum_pct>0?'+':''}${s.momentum_pct}% momentum</span>`
    : '';
  return `<div style="padding:9px 0;border-bottom:1px solid #1a2235">
    <div style="display:flex;justify-content:space-between;align-items:flex-start">
      <span style="font-size:11px;color:#e2e8f0;font-weight:500">${s.repo}</span>
      <span style="font-size:10px;color:${c};font-weight:700">${icon} ${s.direction || 'NORMAL'}</span>
    </div>
    <div style="font-size:9px;color:#4b5563;margin-top:3px;display:flex;gap:12px;flex-wrap:wrap">
      <span>${s.language || '?'} · ${(s.stars||0).toLocaleString()}★</span>
      <span>z = ${s.z_score}</span>
      <span>${s.baseline_wkly} → ${s.recent_wkly} commits/wk</span>
      ${mPill}
      <span style="color:#374151">${s.pct_of_peak}% of peak</span>
    </div>
  </div>`;
}).join('') || '<div style="color:#374151;font-size:10px;padding:8px 0">No commit data available</div>';

// ── Evidence pills ────────────────────────────────────────────────
const EV_STATUS_COLOR = {DETECTED:'#10b981',BURST:'#8b5cf6',OK:'#10b981',PARTIAL:'#f59e0b',NONE:'#4b5563',UNAVAILABLE:'#6b7280',NORMAL:'#3b82f6'};
const evidenceHtml = ['language_shift','repo_growth','velocity_signal','anomaly_detection'].map(key => {
  const e  = (cl.evidence || {})[key] || {};
  const sc = EV_STATUS_COLOR[e.status] || '#4b5563';
  return `<div style="padding:7px 0;border-bottom:1px solid #1a2235">
    <div style="font-size:9px;color:#374151;letter-spacing:.5px;margin-bottom:2px;text-transform:uppercase">${key.replace(/_/g,' ')} · <span style="color:${sc}">${e.status || 'NO DATA'}</span></div>
    <div style="font-size:10px;color:#94a3b8">${e.summary || 'No summary available'}</div>
  </div>`;
}).join('');

// ── Top repos ─────────────────────────────────────────────────────
const topRepoRows = (d.top_repos || []).slice(0, 6).map(r =>
  `<div style="display:flex;justify-content:space-between;align-items:center;padding:6px 0;border-bottom:1px solid #1a2235">
    <span style="font-size:11px;color:#94a3b8">${r.name}</span>
    <div style="font-size:9px;color:#4b5563;text-align:right">
      <span style="color:#e2e8f0;margin-right:8px">${(r.stars||0).toLocaleString()}★</span>
      <span style="margin-right:8px">${r.primary_lang || '?'}</span>
      <span>${r.days_since_push}d ago</span>
    </div>
  </div>`
).join('');

const flagsHtml = (cl.flags || []).length
  ? (cl.flags || []).map(f => pill(f, fc(f))).join(' ')
  : `<span style="color:#1e293b;font-size:9px">no flags raised</span>`;

const riskHtml = (ai.key_risks || []).map(r =>
  `<div style="padding:5px 0;border-bottom:1px solid #1a2235;font-size:10px;color:#ef4444">⚠ ${r}</div>`
).join('') || '<div style="font-size:10px;color:#1e293b;padding:5px 0">No risks flagged by AI</div>';

const oppHtml = (ai.key_opportunities || []).map(o =>
  `<div style="padding:5px 0;border-bottom:1px solid #1a2235;font-size:10px;color:#10b981">✓ ${o}</div>`
).join('') || '<div style="font-size:10px;color:#1e293b;padding:5px 0">No opportunities flagged</div>';

const dirParts = [];
if (edd.what_increased?.length)    dirParts.push(`<span style="color:#10b981">▲ RISING: ${edd.what_increased.join(', ')}</span>`);
if (edd.what_decreased?.length)    dirParts.push(`<span style="color:#ef4444">▼ DECLINING: ${edd.what_decreased.join(', ')}</span>`);
if (edd.newly_appeared?.length)    dirParts.push(`<span style="color:#8b5cf6">✦ NEW: ${edd.newly_appeared.join(', ')}</span>`);
if (edd.stalled_or_dropped?.length)dirParts.push(`<span style="color:#4b5563">✕ DROPPED: ${edd.stalled_or_dropped.join(', ')}</span>`);
const dirHtml = dirParts.join('<br>') || '<span style="color:#1e293b">No directional shift detected</span>';

const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>${d.name} — Engineering Direction Delta · Mycroft</title>
<link rel="preconnect" href="https://fonts.googleapis.com">
<link href="https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,700;0,900;1,400&family=JetBrains+Mono:wght@400;500;700&display=swap" rel="stylesheet">
<style>
  *,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
  html,body{background:#060a12;color:#e2e8f0;font-family:'JetBrains Mono',monospace;font-size:13px;line-height:1.6;min-height:100vh}
  .pg{max-width:1300px;margin:0 auto;padding:0 32px 80px}
  a{color:inherit;text-decoration:none}
</style>
</head>
<body>
<div class="pg">

  <!-- ── MASTHEAD ── -->
  <div style="border-bottom:1px solid #1a2235;padding:32px 0 24px;margin-bottom:36px;display:grid;grid-template-columns:1fr auto;align-items:end;gap:24px">
    <div>
      <div style="font-size:9px;letter-spacing:2.5px;text-transform:uppercase;color:#374151;margin-bottom:8px">
        Mycroft Framework · Intelligence Layer · Tech Stack Directional Signal Agent
      </div>
      <div style="font-family:'Playfair Display',serif;font-size:42px;font-weight:900;color:#f8fafc;line-height:1;letter-spacing:-.5px">
        Engineering Direction Delta
      </div>
      <div style="font-family:'Playfair Display',serif;font-size:24px;font-weight:400;font-style:italic;color:${col};margin-top:8px">
        ${d.name}${d.ticker ? ' (' + d.ticker + ')' : ''}
      </div>
      <div style="font-size:10px;color:#374151;margin-top:6px">
        github.com/${d.org} · ${d.sector} · Run: ${genAt}
      </div>
    </div>
    <div style="text-align:right">
      <div style="font-family:'Playfair Display',serif;font-size:64px;font-weight:900;color:${col};line-height:1">${cl.composite_score}</div>
      <div style="font-size:9px;color:#374151;letter-spacing:.8px;margin-top:4px">COMPOSITE SIGNAL SCORE</div>
      <div style="font-size:14px;font-weight:700;color:${col};margin-top:4px;letter-spacing:1px">${cl.intensity}</div>
      <div style="margin-top:8px">${implPill}</div>
    </div>
  </div>

  <!-- ── SCORE BAR ── -->
  <div style="height:4px;background:#0d1117;border-radius:2px;margin-bottom:32px">
    <div style="height:4px;width:${cl.composite_score}%;background:${col};border-radius:2px;
                box-shadow:0 0 12px ${col}66;transition:width .4s ease"></div>
  </div>

  <!-- ── FLAGS ROW ── -->
  <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin-bottom:32px;
              padding:14px 18px;background:#0d1117;border:1px solid #1a2235">
    <span style="font-size:9px;color:#374151;letter-spacing:.8px;text-transform:uppercase;margin-right:4px">SIGNAL FLAGS</span>
    ${flagsHtml}
    <span style="margin-left:auto;font-size:9px;color:#374151">
      Confidence: <span style="color:#94a3b8">${cl.confidence}%</span> ·
      Human review: <span style="color:${cl.human_review?'#f59e0b':'#10b981'}">${cl.human_review?'REQUIRED':'not required'}</span> ·
      Resolver: <span style="color:#10b981">READY</span>
    </span>
  </div>

  <!-- ── AI SIGNAL ASSESSMENT ── -->
  <div style="background:${bg};border:1px solid ${col}33;border-left:3px solid ${col};padding:20px 24px;margin-bottom:28px">
    <div style="font-size:9px;letter-spacing:1.5px;text-transform:uppercase;color:${col};margin-bottom:10px;opacity:.8">
      AI SIGNAL ASSESSMENT · Groq llama-3.1-8b-instant
    </div>
    <div style="font-family:'Playfair Display',serif;font-size:15px;color:#e2e8f0;line-height:1.7;margin-bottom:12px">
      ${ai.signal_summary || '—'}
    </div>
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;margin-top:14px">
      <div>
        <div style="font-size:9px;color:#374151;letter-spacing:.8px;text-transform:uppercase;margin-bottom:5px">TECHNOLOGY DIRECTION</div>
        <div style="font-size:11px;color:#94a3b8;line-height:1.6">${ai.technology_direction || '—'}</div>
      </div>
      <div>
        <div style="font-size:9px;color:#374151;letter-spacing:.8px;text-transform:uppercase;margin-bottom:5px">VELOCITY ASSESSMENT</div>
        <div style="font-size:11px;color:#94a3b8;line-height:1.6">${ai.velocity_assessment || '—'}</div>
      </div>
    </div>
    ${ai.comparable_moves ? `
    <div style="margin-top:14px;padding-top:12px;border-top:1px solid #1a2235">
      <div style="font-size:9px;color:#374151;letter-spacing:.8px;text-transform:uppercase;margin-bottom:5px">COMPARABLE MARKET MOVES</div>
      <div style="font-size:11px;color:#64748b;font-style:italic">${ai.comparable_moves}</div>
    </div>` : ''}
  </div>

  <!-- ── 4-COLUMN DETAIL GRID ── -->
  <div style="display:grid;grid-template-columns:1fr 1fr 1fr 1fr;gap:2px;margin-bottom:28px">

    <!-- Language Shifts -->
    <div style="background:#0d1117;border:1px solid #1a2235;padding:18px">
      <div style="font-size:9px;letter-spacing:.8px;text-transform:uppercase;color:#374151;margin-bottom:12px">
        LANGUAGE SHIFTS (≥${d.config?.lang_delta_pct || 15}% REL.)
      </div>
      <table style="width:100%;border-collapse:collapse">
        <thead><tr style="border-bottom:1px solid #1a2235">
          <th style="padding:3px 10px 6px 0;font-size:8px;color:#374151;text-align:left;font-weight:400">LANG</th>
          <th style="padding:3px 10px 6px;font-size:8px;color:#374151;text-align:right;font-weight:400">OLDER</th>
          <th style="padding:3px 10px 6px;font-size:8px;color:#374151;text-align:right;font-weight:400">RECENT</th>
          <th style="padding:3px 0 6px 10px;font-size:8px;color:#374151;text-align:left;font-weight:400">SHIFT</th>
        </tr></thead>
        <tbody>${langRows}</tbody>
      </table>
      <div style="margin-top:14px;padding-top:12px;border-top:1px solid #1a2235">
        <div style="font-size:9px;color:#374151;letter-spacing:.8px;text-transform:uppercase;margin-bottom:8px">DIRECTION SUMMARY</div>
        <div style="font-size:10px;line-height:2">${dirHtml}</div>
      </div>
    </div>

    <!-- Commit Velocity -->
    <div style="background:#0d1117;border:1px solid #1a2235;padding:18px">
      <div style="font-size:9px;letter-spacing:.8px;text-transform:uppercase;color:#374151;margin-bottom:12px">
        COMMIT VELOCITY (z ≥ ${d.config?.velocity_z_thresh || 2}σ)
      </div>
      ${velRows}
      <div style="margin-top:14px;padding-top:12px;border-top:1px solid #1a2235">
        <div style="font-size:9px;color:#374151;letter-spacing:.8px;text-transform:uppercase;margin-bottom:6px">OVERALL TREND</div>
        <div style="font-size:13px;font-weight:700;color:${va.overall_trend==='ACCELERATING'?'#10b981':va.overall_trend==='DECELERATING'?'#ef4444':'#4b5563'}">
          ${va.overall_trend || 'STABLE'}
        </div>
        <div style="font-size:9px;color:#374151;margin-top:4px">
          ${va.acceleration_count} accelerating · ${va.deceleration_count} decelerating · ${va.anomaly_count} anomalies
        </div>
      </div>
    </div>

    <!-- Risks & Opportunities -->
    <div style="background:#0d1117;border:1px solid #1a2235;padding:18px">
      <div style="font-size:9px;letter-spacing:.8px;text-transform:uppercase;color:#374151;margin-bottom:12px">KEY RISKS</div>
      ${riskHtml}
      <div style="margin-top:14px;padding-top:12px;border-top:1px solid #1a2235">
        <div style="font-size:9px;letter-spacing:.8px;text-transform:uppercase;color:#374151;margin-bottom:8px">OPPORTUNITIES</div>
        ${oppHtml}
      </div>
    </div>

    <!-- Repo Health + Evidence -->
    <div style="background:#0d1117;border:1px solid #1a2235;padding:18px">
      <div style="font-size:9px;letter-spacing:.8px;text-transform:uppercase;color:#374151;margin-bottom:12px">REPO HEALTH</div>
      ${[
        ['Non-fork repos',     rs.non_fork,            '#e2e8f0'],
        ['Total stars',        (rs.total_stars||0).toLocaleString(), '#f59e0b'],
        ['Active (90d)',       rs.active_90d,           '#10b981'],
        ['Stale (365d+)',      rs.stale_365d,           '#ef4444'],
        ['Recent cohort',      rs.rec_cohort_size + ' repos / ' + d.config?.recent_months + 'm', '#94a3b8'],
        ['Older cohort',       rs.old_cohort_size + ' repos / ' + (d.config?.lookback_months - d.config?.recent_months) + 'm', '#94a3b8'],
        ['Burst ratio',        bd.ratio + 'x baseline', bd.has_burst ? '#f59e0b' : '#4b5563'],
        ['AI topic focus',     d.ai_focus?.recent_ratio + '% recent vs ' + d.ai_focus?.older_ratio + '% older', '#06b6d4'],
      ].map(([label, val, vc]) =>
        `<div style="display:flex;justify-content:space-between;padding:4px 0;border-bottom:1px solid #1a2235">
          <span style="font-size:9px;color:#374151">${label}</span>
          <span style="font-size:10px;color:${vc};font-weight:500">${val}</span>
        </div>`
      ).join('')}

      <div style="margin-top:14px;padding-top:12px;border-top:1px solid #1a2235">
        <div style="font-size:9px;letter-spacing:.8px;text-transform:uppercase;color:#374151;margin-bottom:8px">TOP REPOS</div>
        ${topRepoRows}
      </div>
    </div>

  </div>

  <!-- ── EVIDENCE TRAIL ── -->
  <div style="background:#0d1117;border:1px solid #1a2235;padding:18px 22px;margin-bottom:28px">
    <div style="font-size:9px;letter-spacing:.8px;text-transform:uppercase;color:#374151;margin-bottom:12px">
      EVIDENCE TRAIL — Contradiction Resolver Input
    </div>
    <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(320px,1fr));gap:0">
      ${evidenceHtml}
    </div>
  </div>

  <!-- ── CLAIMS SCHEMA JSON ── -->
  <div style="background:#0d1117;border:1px solid #1a2235;padding:18px 22px;margin-bottom:28px">
    <div style="font-size:9px;letter-spacing:.8px;text-transform:uppercase;color:#374151;margin-bottom:12px">
      MYCROFT CLAIMS SCHEMA OUTPUT — claim_id: ${cl.claim_id}
    </div>
    <pre style="font-size:10px;color:#475569;line-height:1.6;overflow-x:auto;white-space:pre-wrap">${JSON.stringify({
      claim_id:        cl.claim_id,
      agent:           cl.agent,
      schema_version:  cl.schema_version,
      subject:         cl.subject,
      claim_type:      cl.claim_type,
      intensity:       cl.intensity,
      composite_score: cl.composite_score,
      investment_implication: cl.investment_implication,
      flags:           cl.flags,
      engineering_direction_delta: cl.engineering_direction_delta,
      resolver_ready:  cl.resolver_ready,
      human_review:    cl.human_review,
    }, null, 2)}</pre>
  </div>

  <!-- ── FOOTER ── -->
  <div style="border-top:1px solid #1a2235;padding-top:20px;display:flex;justify-content:space-between;font-size:9px;color:#1e293b;flex-wrap:wrap;gap:8px">
    <span>Mycroft Framework · Tech Stack Directional Signal Agent v3 · ${genAt}</span>
    <span>Schema v1.0 · GitHub GraphQL + Groq llama-3.1-8b-instant · Resolver-Ready</span>
  </div>

</div>
</body>
</html>`;

return [{ json: { html } }];

const html  = $input.first().json.html;
const buf   = Buffer.from(html, 'utf8');
const bin   = await this.helpers.prepareBinaryData(buf, 'engineering_direction_delta.html', 'text/html');
return [{
  json:   { filename: 'engineering_direction_delta.html', size_kb: Math.round(buf.length / 1024) },
  binary: { data: bin },
}];

return [{
  json: {
    message: '✅ Report generated! Go to n8n → Export HTML File → Output → Binary → Download'
  }
}];
